// Supabase webhook payload has the new row in body.record
const record = $input.first().json.body.record || $input.first().json.body;
return [{ json: record }];

const entry = $('Extract Entry').first().json;
const projectArr = $('Fetch Project').first().json;
const project = Array.isArray(projectArr) ? projectArr[0] : projectArr;

const systemPrompt = `You are the Tetra Action Item Generator. You transform client voice feedback into structured, implementable action items for the Claude Code agent.

Context:
- Project: ${project.name}
- Tech stack: Next.js, Sanity CMS, Tailwind CSS, Vercel
- Site URL: ${project.site_url || 'N/A'}
- Client language: ${project.metadata?.language || 'en'}

Transform the client feedback into action items. Each must be:
1. Specific enough for Claude Code to implement without questions
2. Scoped to a single change
3. Categorized: code, content, design, config, investigation
4. Prioritized: critical, high, medium, low

If ambiguous, create an "investigation" type item.

Respond ONLY with a JSON array, no markdown, no explanation:
[{ "title": "...", "description": "...", "priority": "...", "type": "..." }]`;

return [{
  json: {
    systemPrompt,
    transcript: entry.raw_transcript,
    entryId: entry.id,
    projectId: entry.project_id,
    intent: entry.intent,
    githubRepo: project.github_repo
  }
}];

const response = $input.first().json;
const entryId = $('Build Claude Prompt').first().json.entryId;
const projectId = $('Build Claude Prompt').first().json.projectId;

// Extract text from Claude response
let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content.map(c => c.text || '').join('');
} else if (typeof response === 'string') {
  text = response;
}

// Clean and parse JSON
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let actionItems;
try {
  actionItems = JSON.parse(text);
} catch(e) {
  // Try to extract JSON array from text
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    actionItems = JSON.parse(match[0]);
  } else {
    actionItems = [{ title: 'Review client feedback', description: 'Could not auto-parse: ' + text.substring(0, 500), priority: 'high', type: 'investigation' }];
  }
}

return [{
  json: {
    actionItems,
    entryId,
    projectId,
    count: actionItems.length
  }
}];

const { actionItems, entryId, projectId } = $input.first().json;

// Build batch insert for Supabase
const rows = actionItems.map(item => ({
  entry_id: entryId,
  project_id: projectId,
  title: item.title,
  description: item.description,
  priority: item.priority || 'medium',
  type: item.type || 'code',
  status: 'pending'
}));

return [{ json: { rows, entryId, projectId } }];
